    94|function parseArgs(argv) {
    95|  const options = { page: 1, outDir: path.join(PROJECT_DIR, "downloads"), limit: 999999 };
    96|  for (let i = 0; i < argv.length; i += 1) {
    97|    const arg = argv[i];
    98|    if (arg === "-h" || arg === "--help") {
    99|      options.help = true;
   100|      continue;
   101|    }
   102|    if (arg === "-p" || arg === "--page") {
   103|      const value = argv[i + 1];
   104|      if (!value) throw new Error(`${arg} requires a page number.`);
   105|      options.page = Number(value);
   106|      i += 1;
   107|      continue;
   108|    }
   109|    if (arg.startsWith("--page=")) {
   110|      options.page = Number(arg.slice("--page=".length));
   111|      continue;
   112|    }
   113|    if (arg === "-o" || arg === "--out") {
   114|      const value = argv[i + 1];
   115|      if (!value) throw new Error(`${arg} requires a folder path.`);
