   123|    }
   124|    if (arg === "-l" || arg === "--limit") {
   125|      const value = argv[i + 1];
   126|      if (!value) throw new Error(`${arg} requires a number.`);
   127|      options.limit = Number(value);
   128|      i += 1;
   129|      continue;
   130|    }
   131|    if (arg.startsWith("--limit=")) {
   132|      options.limit = Number(arg.slice("--limit=".length));
   133|      continue;
   134|    }
   135|    throw new Error(`Unknown option: ${arg}\n\n${usage()}`);
   136|  }
   137|
   138|  if (!Number.isInteger(options.page) || options.page < 1) {
   139|    throw new Error("Page must be a positive integer.");
   140|  }
   141|
   142|  return options;
