   160|function decodeEntities(value) {
   161|  return value
   162|    .replace(/&#(\d+);/g, (_, n) => String.fromCodePoint(Number(n)))
   163|    .replace(/&#x([0-9a-f]+);/gi, (_, n) => String.fromCodePoint(parseInt(n, 16)))
   164|    .replace(/&amp;/g, "&")
   165|    .replace(/&quot;/g, '"')
   166|    .replace(/&#039;/g, "'")
   167|    .replace(/&lt;/g, "<")
   168|    .replace(/&gt;/g, ">");
   169|}
   170|
   171|function stripTags(value) {
   172|  return decodeEntities(value.replace(/<[^>]*>/g, "")).trim().replace(/\s+/g, " ");
   173|}
   174|
   175|function sanitizeFilename(value) {
   176|  const cleaned = value
   177|    .replace(/[<>:"/\\|?*\u0000-\u001f]/g, " ")
   178|    .replace(/\s+/g, " ")
   179|    .trim()
   180|    .replace(/[. ]+$/g, "");
