   199|async function loadUrlRecords() {
   200|  const records = await readJsonFile(URL_RECORD, []);
   201|  const manifest = await readJsonFile(MANIFEST, []);
   202|  const byUrl = new Map();
   203|
   204|  for (const record of records) {
   205|    if (record?.detailUrl) {
   206|      byUrl.set(normalizeDetailUrl(record.detailUrl), {
   207|        ...record,
   208|        detailUrl: normalizeDetailUrl(record.detailUrl),
   209|      });
   210|    }
   211|  }
   212|
   213|  for (const item of manifest) {
   214|    if (!item?.detailUrl || !["downloaded", "skipped-existing", "skipped-detail-url"].includes(item.status)) continue;
   215|    const detailUrl = normalizeDetailUrl(item.detailUrl);
   216|    if (!byUrl.has(detailUrl)) {
