   220|        filePath: item.filePath || null,
   221|        steamUrl: item.steamUrl || null,
   222|        nameSource: item.nameSource || null,
   223|        recordedAt: new Date().toISOString(),
   224|        migratedFromManifest: true,
   225|      });
   226|    }
   227|  }
   228|
   229|  return byUrl;
