   232|async function saveUrlRecords(recordsByUrl) {
   233|  const records = [...recordsByUrl.values()].sort((a, b) => a.detailUrl.localeCompare(b.detailUrl));
   234|  await writeFile(URL_RECORD, JSON.stringify(records, null, 2), "utf8");
