   275|async function fetchWithRetry(url, options, label) {
   276|  let lastError;
   277|  for (let attempt = 1; attempt <= FETCH_RETRIES; attempt += 1) {
   278|    try {
   279|      return await fetch(url, { ...options, signal: AbortSignal.timeout(90000) });
   280|    } catch (error) {
   281|      lastError = error;
   282|      const reason = describeFetchError(error);
   283|      if (attempt === FETCH_RETRIES) break;
   284|      console.warn(`${label} failed (${reason}); retrying ${attempt}/${FETCH_RETRIES - 1}...`);
   285|      await sleep(FETCH_RETRY_DELAY_MS * attempt);
   286|    }
   287|  }
   288|  throw new Error(`${label} failed after ${FETCH_RETRIES} attempts: ${describeFetchError(lastError)}`);
