   291|async function fetchText(url) {
   292|  return runCurlCapture(
   293|    [
   294|      "-fsSL",
   295|      "--retry",
   296|      String(FETCH_RETRIES),
   297|      "--retry-delay",
   298|      String(FETCH_RETRY_DELAY_MS / 1000),
   299|      "--retry-all-errors",
   300|      "--connect-timeout",
   301|      "20",
   302|      "--max-time",
   303|      "90",
   304|      "-A",
   305|      USER_AGENT,
   306|      url,
   307|    ],
   308|    `Fetch ${url}`,
   309|  );
