   312|function parsePageItems(html) {
   313|  const sectionStart = html.indexOf("<span>Latest Videos</span>");
   314|  const scoped = sectionStart >= 0 ? html.slice(sectionStart) : html;
   315|  const matches = [
   316|    ...scoped.matchAll(
   317|      /<h3 class="[^"]*\bentry-title\b[^"]*">\s*<a href="([^"]+)"[^>]*>([\s\S]*?)<\/a>\s*<\/h3>/gi,
   318|    ),
   319|  ];
   320|  const seen = new Set();
   321|  const items = [];
   322|  for (const match of matches) {
   323|    const url = decodeEntities(match[1]);
   324|    if (seen.has(url)) continue;
   325|    seen.add(url);
   326|    items.push({ detailUrl: url, pageTitle: stripTags(match[2]) });
   327|    if (items.length === 15) break;
   328|  }
   329|  return items;
