   331|
   332|function parseDetail(html) {
   333|  const h1 = html.match(/<h1[^>]*class="[^"]*\bentry-title\b[^"]*"[^>]*>([\s\S]*?)<\/h1>/i);
   334|  const titleMatch =
   335|    h1 || html.match(/<meta property="og:title" content="([^"]+)"/i) || html.match(/<title>([\s\S]*?)<\/title>/i);
   336|  const fallbackTitle = titleMatch ? stripTags(titleMatch[1]).replace(/\s+-\s+MoeWalls$/i, "") : "wallpaper";
   337|
   338|  const downloadMatch = html.match(/id="moe-download"[\s\S]*?data-url="([^"]+)"/i);
   339|  const downloadToken = downloadMatch ? decodeEntities(downloadMatch[1]) : null;
   340|
   341|  const jumpMatch = html.match(/<form[^>]+action="\/jump\.php\?url=([^"]+)"[^>]*>[\s\S]*?steamcommunity\.com/i);
   342|  const steamUrl = jumpMatch ? Buffer.from(decodeEntities(jumpMatch[1]), "base64").toString("utf8") : null;
   343|
   344|  return { fallbackTitle, downloadToken, steamUrl };
