   347|function parseSteamTitle(html) {
   348|  const workshop = html.match(/<div class="workshopItemTitle">([\s\S]*?)<\/div>/i);
   349|  if (workshop) return stripTags(workshop[1]);
   350|  const title = html.match(/<title>Steam Workshop::([\s\S]*?)<\/title>/i);
