    16|import { mkdir, readFile, writeFile, stat } from "node:fs/promises";
    17|import { Buffer } from "node:buffer";
    18|import { spawn } from "node:child_process";
    19|import path from "node:path";
    20|import { fileURLToPath } from "node:url";
    21|
    22|const ROOT = "https://wallpaperwaifu.com/";
